                                className="repost-submit-btn caption-editor-save-btn"
                                onClick={handleSaveRepostCaption}
                                disabled={isSavingCaption}
                            >
                                {isSavingCaption ? 'Saving...' : 'Save'}
                            </button>
                        </div>
                    </motion.div>
                </motion.div>
            </AnimatePresence>,
            document.body
        )}
        </>
    )
}

export default ProfilePostCards;

